// ==========================================
// CONFIGURACION VIP (Actualizada)
// ==========================================
const MY_PC_IP = env.get('MY_PC_IP') || "192.168.1.218";
const ROUTER_IP = env.get('ROUTER_IP') || "192.168.1.1";
const PRIVACY_TTL_MS = 2 * 60 * 60 * 1000; // 2 horas

// ==========================================
// PREPARACION
// ==========================================
let devices = [];
const scanStartTs = Date.now();
const rawOutput = (msg.payload || "").toString();
const lines = rawOutput.split('\n');
const ipRegex = /(\d{1,3}(?:\.\d{1,3}){3})/;

// Limpieza de privacidad para mapa de alias
const nameMapRaw = global.get("deviceNames") || {};
const nameMap = {};

for (const [ip, val] of Object.entries(nameMapRaw)) {
    if (!val) continue;

    if (typeof val === "string") {
        nameMap[ip] = { alias: val, ts: scanStartTs, consent: true };
        continue;
    }

    if (typeof val === "object") {
        const alias = (val.alias || val.nombre || "Invitado").toString();
        const ts = Number(val.ts || 0);

        if (!ts || (scanStartTs - ts) <= PRIVACY_TTL_MS) {
            nameMap[ip] = {
                alias,
                ts: ts || scanStartTs,
                consent: !!val.consent
            };
        }
    }
}

global.set("deviceNames", nameMap);

let metrics = global.get("esc1_metrics") || {};
metrics.scan_total = Number(metrics.scan_total || 0);
metrics.hosts_new_total = Number(metrics.hosts_new_total || 0);
metrics.discovery_delay_samples_ms = Array.isArray(metrics.discovery_delay_samples_ms) ? metrics.discovery_delay_samples_ms : [];
metrics.dns_latency_samples_ms = Array.isArray(metrics.dns_latency_samples_ms) ? metrics.dns_latency_samples_ms : [];
metrics.privacy_purges_total = Number(metrics.privacy_purges_total || 0);
metrics.mode_actual = "real";
metrics.last_scan_start_ts = scanStartTs;

let currentIP = null;
let currentName = "Dispositivo Desconocido";
let currentVendor = "Desconocido";

function getAliasByIP(ip) {
    const val = nameMap[ip];
    if (!val) return "";
    if (typeof val === "string") return val;
    if (typeof val === "object") return (val.alias || val.nombre || "").toString();
    return "";
}

function pushBounded(arr, value, maxSize) {
    arr.push(value);
    if (arr.length > maxSize) {
        arr.splice(0, arr.length - maxSize);
    }
}

function processDevice(ip, name, vendor) {
    let os = "Desconocido";
    let nameLower = (name || "").toLowerCase();
    let vendorLower = (vendor || "").toLowerCase();

    if (ip === ROUTER_IP || nameLower.includes('gateway') || nameLower.includes('openwrt')) {
        os = "Router";
        name = "Router OpenWrt (Nucleo)";
    }
    else if (
        nameLower.includes('win') || nameLower.includes('pc') ||
        nameLower.includes('laptop') || nameLower.includes('desktop') ||
        nameLower.includes('ubuntu') || nameLower.includes('kali') ||
        nameLower.includes('asus') ||
        vendorLower.includes('asus') || vendorLower.includes('intel') ||
        vendorLower.includes('msi') || vendorLower.includes('hp') ||
        vendorLower.includes('dell') || vendorLower.includes('lenovo') ||
        vendorLower.includes('acer')
    ) {
        os = "Windows/Linux";
    }
    else if (nameLower.includes('android') || vendorLower.includes('samsung') || vendorLower.includes('xiaomi') || vendorLower.includes('huawei') || vendorLower.includes('motorola')) {
        os = "Android";
    }
    else if (nameLower.includes('iphone') || vendorLower.includes('apple')) {
        os = "iOS";
    }

    const alias = getAliasByIP(ip);
    if (alias) {
        name = "Alias: " + alias;
    }

    if (ip === MY_PC_IP || nameLower.includes("jeanpoll")) {
        name = "jeanpoll-ASUS (Admin)";
        os = "Windows/Linux";
        vendor = "ASUS TUF";
    }

    let sitioVisitado = global.get("sitio_" + ip) || global.get("sitio_::ffff:" + ip) || "En espera de trafico...";

    const dnsTs = Number(global.get("dns_ts_" + ip) || global.get("dns_ts_::ffff:" + ip) || 0);
    if (dnsTs > 0) {
        const latMs = Date.now() - dnsTs;
        if (latMs >= 0 && latMs <= 600000) {
            pushBounded(metrics.dns_latency_samples_ms, latMs, 400);
            metrics.dns_latency_last_ms = latMs;
        }
    }

    devices.push({
        "Nombre": name,
        "IP": ip,
        "Fabricante": vendor,
        "OS": os,
        "sitio_actual": sitioVisitado
    });
}

for (const lineRaw of lines) {
    const line = (lineRaw || "").trim();
    if (!line) continue;

    if (line.startsWith("Nmap scan report for")) {
        if (currentIP) processDevice(currentIP, currentName, currentVendor);

        currentIP = null;
        currentName = "Dispositivo Desconocido";
        currentVendor = "Desconocido";

        const report = line.replace("Nmap scan report for", "").trim();
        const named = report.match(/^(.*?)\s+\((\d{1,3}(?:\.\d{1,3}){3})\)$/);
        if (named) {
            currentName = named[1];
            currentIP = named[2];
        } else {
            const ipOnly = report.match(/^(\d{1,3}(?:\.\d{1,3}){3})$/);
            if (ipOnly) {
                currentIP = ipOnly[1];
            } else {
                const ipFallback = report.match(ipRegex);
                if (ipFallback) currentIP = ipFallback[1];
                if (report && report !== currentIP && !/^_gateway/i.test(report)) {
                    currentName = report;
                }
            }
        }
        continue;
    }

    if (currentIP && line.includes("MAC Address:")) {
        let vendorMatch = line.match(/\((.*?)\)/);
        if (vendorMatch && vendorMatch[1] && vendorMatch[1] !== "Unknown") {
            currentVendor = vendorMatch[1];
        }
    }
}

if (currentIP) processDevice(currentIP, currentName, currentVendor);

const uniqueDevices = [];
const seenIPs = new Set();
for (const dev of devices) {
    if (!seenIPs.has(dev.IP)) {
        seenIPs.add(dev.IP);
        uniqueDevices.push(dev);
    }
}

let seenHosts = global.get("esc1_seen_hosts") || {};
for (const dev of uniqueDevices) {
    if (!seenHosts[dev.IP]) {
        seenHosts[dev.IP] = Date.now();
        metrics.hosts_new_total += 1;

        const joinTs = Number(global.get("esc1_join_" + dev.IP) || 0);
        if (joinTs > 0) {
            const delay = Date.now() - joinTs;
            if (delay >= 0 && delay <= 600000) {
                pushBounded(metrics.discovery_delay_samples_ms, delay, 300);
                metrics.discovery_delay_last_ms = delay;
            }
        }
    }
}

global.set("esc1_seen_hosts", seenHosts);

const scanEndTs = Date.now();
metrics.scan_total += 1;
metrics.last_scan_end_ts = scanEndTs;
metrics.last_scan_duration_ms = scanEndTs - scanStartTs;
metrics.hosts_visible = uniqueDevices.length;

if (!metrics.mount_start_ts) {
    metrics.mount_start_ts = scanStartTs;
}
if (!metrics.first_scan_ready_ts) {
    metrics.first_scan_ready_ts = scanEndTs;
}
if (metrics.mount_start_ts && metrics.first_scan_ready_ts) {
    metrics.mount_time_ms = metrics.first_scan_ready_ts - metrics.mount_start_ts;
}

global.set("esc1_metrics", metrics);

global.set("esc1_last_devices", uniqueDevices);

msg.payload = uniqueDevices;
msg.routerIP = ROUTER_IP;
return msg;

var ssid = msg.payload.ssid;
var routerPass = env.get('ROUTER_PASS') || '';
var routerIP = env.get('ROUTER_IP') || '192.168.1.1';

// --- 1. COMANDO ROUTER (SSH) ---
// Cambia SSID y quita contraseña (Open)
var uciCmds = `uci set wireless.wifinet2.ssid='${ssid}' && uci set wireless.wifinet2.encryption='none' && uci commit wireless && wifi reload`;
var sshFullCmd = `sshpass -p '${routerPass}' ssh -o StrictHostKeyChecking=no root@${routerIP} "${uciCmds}"`;
var msgSSH = { payload: sshFullCmd };

// --- 2. GENERAR QR WIFI (Para la siguiente pestaña) ---
// Formato red abierta: WIFI:T:nopass;S:nombre;;
var qrString = `WIFI:T:nopass;S:${ssid};;`;
var msgQR = { payload: qrString };

// Salida 1: SSH | Salida 2: Template QR
return [msgSSH, msgQR];

// 1. IP del servidor: se detecta automáticamente con hostname -I
var myIP = (msg.payload || '').toString().trim();

// 2. Fallback: variable de entorno DASH_IP
if (!myIP || myIP.length < 7) {
    myIP = env.get('DASH_IP') || '';
}

// 3. Si no hay IP disponible, no generar QR incorrecto
if (!myIP) {
    node.warn('QR Dashboard: hostname -I no devolvió IP y DASH_IP no está configurado en .env');
    return null;
}

// 4. Puerto
var dashPort = (env.get('DASH_PORT') || '1881').toString().trim();
if (!dashPort) dashPort = '1881';

// 5. URL final
var url = 'http://' + myIP + ':' + dashPort + '/registro';
msg.payload = url;
return msg;

let logTexto = (msg.payload || "").toString().trim();
let now = Date.now();

let metrics = global.get("esc1_metrics") || {};
metrics.dns_events_total = Number(metrics.dns_events_total || 0) + 1;
metrics.dns_events_descartados = Number(metrics.dns_events_descartados || 0);
metrics.dns_events_validos = Number(metrics.dns_events_validos || 0);
metrics.dns_privado_detectado_total = Number(metrics.dns_privado_detectado_total || 0);
metrics.no_autorizado_detectado_total = Number(metrics.no_autorizado_detectado_total || 0);
metrics.sim_tests_total = Number(metrics.sim_tests_total || 0);
metrics.sim_tests_ok = Number(metrics.sim_tests_ok || 0);
metrics.dns_ipv6_total = Number(metrics.dns_ipv6_total || 0);
metrics.dns_ipv6_mapped_total = Number(metrics.dns_ipv6_mapped_total || 0);
metrics.dns_ipv6_unmapped_total = Number(metrics.dns_ipv6_unmapped_total || 0);
metrics.ui_push_total = Number(metrics.ui_push_total || 0);

function saveMetrics() {
    global.set("esc1_metrics", metrics);
}

if (!logTexto.includes("query[")) {
    metrics.dns_events_descartados += 1;
    saveMetrics();
    return null;
}

let regex = /query\[([A-Za-z0-9_-]+)\]\s+([^\s]+)\s+from\s+([a-fA-F0-9:.\[\]%]+)/;
let coincidencia = logTexto.match(regex);

let queryType = "";
let dominioCrudo = "";
let ipRaw = "";

if (coincidencia && coincidencia.length >= 4) {
    queryType = (coincidencia[1] || "").toUpperCase();
    dominioCrudo = (coincidencia[2] || "").toLowerCase().replace(/\.$/, "");
    ipRaw = (coincidencia[3] || "").trim();
} else {
    let fallback = logTexto.match(/query\[[^\]]+\]\s+([^\s]+).*?\sfrom\s+([^\s]+)/i);
    if (!fallback || fallback.length < 3) {
        metrics.dns_events_descartados += 1;
        saveMetrics();
        return null;
    }

    dominioCrudo = (fallback[1] || "").toLowerCase().replace(/\.$/, "");
    ipRaw = (fallback[2] || "").trim();
}

ipRaw = ipRaw.replace(/[;,]$/, "");

function normalizarIP(ip) {
    if (!ip) return "";

    let salida = ip.trim().replace(/^\[|\]$/g, "");

    if (salida.includes("%")) {
        salida = salida.split("%")[0];
    }

    if (salida.startsWith("::ffff:")) {
        salida = salida.substring(7);
    }

    let ipv4AlFinal = salida.match(/(\d{1,3}(?:\.\d{1,3}){3})$/);
    if (ipv4AlFinal) {
        return ipv4AlFinal[1];
    }

    return salida;
}

function dominioBase(dominio) {
    let partes = dominio.split(".").filter(Boolean);
    if (partes.length < 2) return dominio;

    let tld = partes[partes.length - 1];
    let sld = partes[partes.length - 2];

    if (partes.length >= 3 && tld.length === 2 && sld.length <= 3) {
        return partes[partes.length - 3] + "." + sld + "." + tld;
    }

    return sld + "." + tld;
}

let ipOrigen = normalizarIP(ipRaw);
if (!dominioCrudo || !ipOrigen) {
    metrics.dns_events_descartados += 1;
    saveMetrics();
    return null;
}

const ruidoPatterns = [
    ".arpa",
    ".lan",
    "connectivity-check",
    "connectivitycheck",
    "clients3.google.com",
    "msftconnecttest",
    "dns.msftncsi.com",
    "time.android.com",
    "google-analytics",
    "doubleclick.net",
    "optimizationguide"
];

if (ruidoPatterns.some((p) => dominioCrudo.includes(p))) {
    metrics.dns_events_descartados += 1;
    saveMetrics();
    return null;
}

let mapIp6to4 = global.get("esc1_ip6_to_ip4") || {};
let recentV4 = global.get("esc1_recent_dns_v4") || [];
let recentV6 = global.get("esc1_recent_dns_v6") || [];

if (!Array.isArray(recentV4)) recentV4 = [];
if (!Array.isArray(recentV6)) recentV6 = [];

const correlateMs = 5000;
const keepMs = 30000;

recentV4 = recentV4.filter((e) => e && e.ip && e.dom && (now - Number(e.ts || 0)) <= keepMs);
recentV6 = recentV6.filter((e) => e && e.ip && e.dom && (now - Number(e.ts || 0)) <= keepMs);

const isIPv6 = ipOrigen.includes(":");
let ipObjetivo = ipOrigen;

if (isIPv6) {
    metrics.dns_ipv6_total += 1;

    if (mapIp6to4[ipOrigen]) {
        ipObjetivo = mapIp6to4[ipOrigen];
        metrics.dns_ipv6_mapped_total += 1;
    } else {
        const candidateV4 = Array.from(new Set(
            recentV4
                .filter((e) => e.dom === dominioCrudo && (now - Number(e.ts || 0)) <= correlateMs)
                .map((e) => e.ip)
        ));

        if (candidateV4.length === 1) {
            ipObjetivo = candidateV4[0];
            mapIp6to4[ipOrigen] = ipObjetivo;
            metrics.dns_ipv6_mapped_total += 1;
        } else {
            metrics.dns_ipv6_unmapped_total += 1;
        }

        recentV6.push({ ip: ipOrigen, dom: dominioCrudo, ts: now });
    }
} else {
    const candidateV6 = Array.from(new Set(
        recentV6
            .filter((e) => e.dom === dominioCrudo && (now - Number(e.ts || 0)) <= correlateMs)
            .map((e) => e.ip)
    ));

    if (candidateV6.length === 1 && !mapIp6to4[candidateV6[0]]) {
        mapIp6to4[candidateV6[0]] = ipOrigen;
    }

    recentV4.push({ ip: ipOrigen, dom: dominioCrudo, ts: now });
}

global.set("esc1_ip6_to_ip4", mapIp6to4);
global.set("esc1_recent_dns_v4", recentV4.slice(-300));
global.set("esc1_recent_dns_v6", recentV6.slice(-300));
metrics.dns_ip_objetivo_last = ipObjetivo;

let servicioLimpio = "";
let score = 50;
let categoriaBloqueo = "";

const adultPatterns = /(porn|xxx|xvideos|xhamster|xnxx|redtube|youporn|pornhub|brazzers|chaturbate)/;
const piracyPatterns = /(thepiratebay|1337x|yts\.|yify|kickass|rarbg|cuevana|pelisplus|repelis|gnula|torrent)/;

if (adultPatterns.test(dominioCrudo)) {
    servicioLimpio = "No Autorizado";
    categoriaBloqueo = "adulto";
    score = 120;
    metrics.no_autorizado_detectado_total += 1;
}
else if (piracyPatterns.test(dominioCrudo)) {
    servicioLimpio = "No Autorizado";
    categoriaBloqueo = "pirateria";
    score = 120;
    metrics.no_autorizado_detectado_total += 1;
}
else if (/dns\.google|cloudflare-dns\.com|one\.one\.one\.one|dns\.quad9\.net|nextdns\.io|doh\./.test(dominioCrudo)) {
    servicioLimpio = "DNS Privado";
    score = 15;
    metrics.dns_privado_detectado_total += 1;
}
else if (/tiktok|tiktokcdn|byteoversea|bytedance|musical\.ly|ibytedtos/.test(dominioCrudo)) {
    servicioLimpio = "TikTok";
    score = 110;
}
else if (/instagram|cdninstagram|igcdn|igsn|i\.instagram|ig\.me|threads\.net/.test(dominioCrudo)) {
    servicioLimpio = "Instagram";
    score = 110;
}
else if (/whatsapp|whatsapp\.net|wa\.me/.test(dominioCrudo)) {
    servicioLimpio = "WhatsApp";
    score = 110;
}
else if (/facebook|fbcdn|fbsbx|fb\.com|messenger/.test(dominioCrudo)) {
    servicioLimpio = "Facebook";
    score = 110;
}
else if (/youtube|youtu\.be|googlevideo|ytimg/.test(dominioCrudo)) {
    servicioLimpio = "YouTube";
    score = 110;
}
else if (dominioCrudo.includes("epn.edu.ec")) {
    if (dominioCrudo.includes("aulasvirtuales")) {
        servicioLimpio = "Aulas Virtuales EPN";
        score = 160;
    } else {
        servicioLimpio = "Portal EPN";
        score = 145;
    }
}
else if (/google\.com|googleapis\.com|gstatic\.com|gvt1\.com|1e100\.net/.test(dominioCrudo)) {
    servicioLimpio = "Google";
    score = 30;
}
else {
    servicioLimpio = dominioBase(dominioCrudo);
    score = 60;
}

const stateKey = "trafico_estado_" + ipObjetivo;
const holdMs = 8000;
const minInitialScore = 30;
let estadoPrevio = global.get(stateKey);

let actualizar = false;
if (!estadoPrevio) {
    actualizar = score >= minInitialScore;
} else if (score > (estadoPrevio.score || 0)) {
    actualizar = true;
} else if (score === (estadoPrevio.score || 0) && servicioLimpio !== estadoPrevio.servicio) {
    actualizar = true;
} else if (servicioLimpio === estadoPrevio.servicio) {
    if (score >= 50 || (estadoPrevio.score || 0) >= 50) {
        actualizar = true;
    } else if (score >= minInitialScore && (now - (estadoPrevio.ts || 0)) > holdMs) {
        actualizar = true;
    }
} else if ((now - (estadoPrevio.ts || 0)) > holdMs && score >= 50) {
    actualizar = true;
}

let estadoActual = estadoPrevio;
if (actualizar) {
    estadoActual = {
        servicio: servicioLimpio,
        dominio_real: dominioCrudo,
        score: score,
        categoria_bloqueo: categoriaBloqueo || undefined,
        ts: now
    };

    global.set(stateKey, estadoActual);
    global.set("sitio_" + ipObjetivo, estadoActual.servicio);
    global.set("dns_ts_" + ipObjetivo, now);

    if (ipOrigen && ipOrigen !== ipObjetivo) {
        global.set("sitio_" + ipOrigen, estadoActual.servicio);
        global.set("dns_ts_" + ipOrigen, now);
    }

    if (ipRaw && ipRaw !== ipObjetivo && ipRaw !== ipOrigen) {
        global.set("sitio_" + ipRaw, estadoActual.servicio);
        global.set("dns_ts_" + ipRaw, now);
    }
}
else {
    const prevScore = estadoActual && typeof estadoActual.score === "number" ? estadoActual.score : 0;
    const prevTs = estadoActual && estadoActual.ts ? estadoActual.ts : 0;

    if (prevScore < 50 && score < 50 && (now - prevTs) > holdMs) {
        estadoActual = {
            servicio: "En espera de trafico util...",
            dominio_real: dominioCrudo,
            score: 0,
            ts: now
        };

        global.set(stateKey, estadoActual);
        global.set("sitio_" + ipObjetivo, estadoActual.servicio);
        global.set("dns_ts_" + ipObjetivo, now);

        if (ipOrigen && ipOrigen !== ipObjetivo) {
            global.set("sitio_" + ipOrigen, estadoActual.servicio);
            global.set("dns_ts_" + ipOrigen, now);
        }
    } else if (!estadoActual) {
        estadoActual = {
            servicio: "En espera de trafico util...",
            dominio_real: dominioCrudo,
            score: 0,
            ts: now
        };

        global.set(stateKey, estadoActual);
        global.set("sitio_" + ipObjetivo, estadoActual.servicio);
        global.set("dns_ts_" + ipObjetivo, now);

        if (ipOrigen && ipOrigen !== ipObjetivo) {
            global.set("sitio_" + ipOrigen, estadoActual.servicio);
            global.set("dns_ts_" + ipOrigen, now);
        }
    }
}

metrics.dns_events_validos += 1;
metrics.dns_events_last_ts = now;
metrics.dns_query_type_last = queryType || null;
metrics.dns_domain_last = dominioCrudo;
metrics.dns_ip_last = ipOrigen;

if (msg.expected_service) {
    metrics.sim_tests_total += 1;
    const esperado = (msg.expected_service || "").toString().trim().toLowerCase();
    const actual = ((estadoActual ? estadoActual.servicio : servicioLimpio) || "").toString().trim().toLowerCase();
    if (esperado && actual && esperado === actual) {
        metrics.sim_tests_ok += 1;
    }
}

msg.payload = {
    ip: ipObjetivo,
    ip_origen: ipOrigen,
    ip_raw: ipRaw,
    query_type: queryType || null,
    dominio_real: dominioCrudo,
    servicio: estadoActual ? estadoActual.servicio : servicioLimpio,
    servicio_detectado: servicioLimpio,
    score_detectado: score,
    categoria_bloqueo: categoriaBloqueo || null
};

let msgUi = null;
const cachedDevices = global.get("esc1_last_devices");
if (Array.isArray(cachedDevices) && cachedDevices.length > 0) {
    const lastUiPushTs = Number(global.get("esc1_ui_last_push_ts") || 0);
    const uiThrottleMs = 500;

    if ((now - lastUiPushTs) >= uiThrottleMs) {
        const refreshedDevices = cachedDevices.map((dev) => {
            const ipDev = (dev && dev.IP ? dev.IP : "").toString();
            if (!ipDev) return dev;

            const sitio =
                global.get("sitio_" + ipDev) ||
                global.get("sitio_::ffff:" + ipDev) ||
                dev.sitio_actual ||
                "En espera de trafico...";

            return Object.assign({}, dev, { sitio_actual: sitio });
        });

        global.set("esc1_last_devices", refreshedDevices);
        global.set("esc1_ui_last_push_ts", now);
        metrics.ui_push_total += 1;
        msgUi = { payload: refreshedDevices };
    }
}

saveMetrics();
return [msg, msgUi];

let metrics = global.get('esc1_metrics') || {};
if (!metrics.mount_start_ts) {
    metrics.mount_start_ts = Date.now();
    global.set('esc1_metrics', metrics);
}
return null;

const ttlMs = 2 * 60 * 60 * 1000;
const now = Date.now();

let nameMap = global.get('deviceNames') || {};
const before = Object.keys(nameMap).length;
const cleaned = {};

for (const [ip, val] of Object.entries(nameMap)) {
    if (typeof val === 'string') {
        cleaned[ip] = { alias: val, ts: now, consent: true };
        continue;
    }

    if (val && typeof val === 'object') {
        const ts = Number(val.ts || 0);
        const alias = (val.alias || val.nombre || '').toString();
        if (alias && (!ts || (now - ts) <= ttlMs)) {
            cleaned[ip] = { alias: alias, ts: ts || now, consent: !!val.consent };
        }
    }
}

global.set('deviceNames', cleaned);

const removed = before - Object.keys(cleaned).length;
let metrics = global.get('esc1_metrics') || {};
metrics.privacy_last_purge_ts = now;
metrics.privacy_last_removed = removed;
metrics.privacy_purges_total = Number(metrics.privacy_purges_total || 0) + 1;

global.set('esc1_metrics', metrics);
return null;

function p95(arr) {
    if (!Array.isArray(arr) || arr.length === 0) return null;
    const sorted = arr.slice().sort((a,b) => a-b);
